  {
    "file": "src/Components/Web/src/Forms/ExpressionMemberAccessor.cs",
    "line": 89,
    "severity": "critical",
    "description": "ClearCache() only clears _memberInfoCache but not _displayNameCache. After hot reload, stale cached display names will persist, causing the component to render incorrect display names. Both caches must be cleared together on metadata updates.",
    "fix_patch": "--- a/src/Components/Web/src/Forms/ExpressionMemberAccessor.cs
+++ b/src/Components/Web/src/Forms/ExpressionMemberAccessor.cs
@@ -86,5 +86,6 @@
     private static void ClearCache()
     {
         _memberInfoCache.Clear();
+        _displayNameCache.Clear();
     }
"
  },
  {
    "file": "src/Components/Web/src/Forms/DisplayName.cs",
    "line": 35,
    "severity": "high",
    "description": "Component always re-renders on every SetParametersAsync call, even when the expression reference hasn't changed. The _previousFieldAccessor field is declared but never used. This violates Blazor component conventions - components should only render when parameters actually change. This causes unnecessary rendering and performance issues, especially in lists.",
    "fix_patch": "--- a/src/Components/Web/src/Forms/DisplayName.cs
+++ b/src/Components/Web/src/Forms/DisplayName.cs
@@ -35,10 +35,17 @@
     Task IComponent.SetParametersAsync(ParameterView parameters)
     {
         parameters.SetParameterProperties(this);

+        ArgumentNullException.ThrowIfNull(For);
+
+        if (!ReferenceEquals(For, _previousFieldAccessor))
+        {
-        var newDisplayName = ExpressionMemberAccessor.GetDisplayName(For);
-        _displayName = newDisplayName;
-        _renderHandle.Render(BuildRenderTree);
+            var newDisplayName = ExpressionMemberAccessor.GetDisplayName(For);
+            _displayName = newDisplayName;
+            _renderHandle.Render(BuildRenderTree);
+            _previousFieldAccessor = For;
+        }

         return Task.CompletedTask;
     }
"
  },
  {
    "file": "src/Components/Web/src/Forms/ExpressionMemberAccessor.cs",
    "line": 57,
    "severity": "high",
    "description": "Attribute precedence is reversed. DisplayNameAttribute is checked before DisplayAttribute, but the correct precedence should check DisplayAttribute first (it is the more modern and comprehensive attribute with additional metadata like Description and Order). This causes [DisplayName] attributes to incorrectly override [Display] attributes.",
    "fix_patch": "--- a/src/Components/Web/src/Forms/ExpressionMemberAccessor.cs
+++ b/src/Components/Web/src/Forms/ExpressionMemberAccessor.cs
@@ -56,18 +56,18 @@

         return _displayNameCache.GetOrAdd(member, static m =>
         {
+            var displayAttribute = m.GetCustomAttribute<DisplayAttribute>();
+            if (displayAttribute is not null)
+            {
+                var name = displayAttribute.GetName();
+                if (name is not null)
+                {
+                    return name;
+                }
+            }
+
             var displayNameAttribute = m.GetCustomAttribute<DisplayNameAttribute>();
             if (displayNameAttribute?.DisplayName is not null)
             {
                 return displayNameAttribute.DisplayName;
             }

-            var displayAttribute = m.GetCustomAttribute<DisplayAttribute>();
-            if (displayAttribute is not null)
-            {
-                var name = displayAttribute.GetName();
-                if (name is not null)
-                {
-                    return name;
-                }
-            }
-
             return m.Name;
         });
     }
"
  }
]

